const intervalInit = 10000;

function baixar() {
    const aulas = document.querySelectorAll(".LessonList-item > section > div > div > div > a");
    const len = aulas.length;  //quantidade total de aulas
    console.log("total de aulas: " + len);
    let midelayinit = preTimer(Math.round(intervalInit / 1000));
    let interAM = setInterval(getMaiorAula, intervalInit, aulas, len, midelayinit);
    let cont2 = 0;    //contador do getMaiorAula
    let miInter = 0;
    let cont = 0;
    let lin_global = []; //quantidade de videos na aula
    let lenAM = 0;
    let midelay = 0;
    let aula = document.querySelectorAll(".LessonList-item>section>div>div>div>a>header>div>div>h2");
    //funcao para encontrar a aula de maior comprimento
    function getMaiorAula(aulas, len, midelayinit) {
        clearInterval(midelayinit);
        if (cont2 < len) {
            aulas[cont2].click();
            let midelayinit1 = preTimer(Math.round((intervalInit / 1.2) / 1000));
            setTimeout(() => {
                let lin_ = document.querySelectorAll('[class="ListVideos-items-video"]>a').length;
                console.log("length desta aula: " + lin_);
                getPdf(); //download temporario para corrigir o problema que descobrimos
                lin_global.push(lin_);
                if (lin_ > lenAM) {
                    lenAM = lin_;
                }
                clearInterval(midelayinit1);
            }, intervalInit / 1.2);
            cont2++;
        } else {
            clearInterval(interAM);
        }
        console.log(lin_global);
    }
    function showTimer(t) {
        t--;
        console.log('delay: ' + t + 's');
        return t;
    }
    function preTimer(t) {
        let midelay = setInterval(() => {
            let u = showTimer(t);
            t = u;
        }, 1000, t);
        return midelay;
    }

    function getPdf() {
        let pdfs = document.getElementsByClassName("LessonButton");
        for (item of pdfs) {
            if (item.innerText != "Fórum de Dúvidas" && item.innerText != "Caderno de Questões") {
                item.click();
            }
        }
    }
}
baixar();












