let pdfs = [];

let myInterval = setInterval(() => {
    let iframe2 = document.createElement('iframe');
    iframe2.name = 'meuiframe';

    const a = document.createElement('a');
    if (pdfs.length > 0) {
        a.href = pdfs[0];
        a.target = 'meuiframe';
        a.click();
        pdfs.shift();
    }
}, 10000);

async function baixar(url, nome) {   //função para baixar um item por vez
    console.log("Iniciando download:", url);
    if (url.indexOf("https://api") == 0) {
        pdfs.push(url);
        //await baixarPdf(url);  	
    } else {
        // Criar iframe limpo com contexto próprio
        const iframe = document.createElement("iframe");
        iframe.style.display = "none";
        document.body.appendChild(iframe);

        const NativeURL = iframe.contentWindow.URL; // URL verdadeiro
        const NativeBlob = iframe.contentWindow.Blob; // às vezes também é sobrescrito

        const resposta = await fetch(url);
        const blob = new NativeBlob([await resposta.arrayBuffer()]);

        console.log("Download concluído!");

        const a = document.createElement("a");
        a.href = NativeURL.createObjectURL(blob);
        if (url.indexOf('.mp4') > 0) {
            a.download = nome || "arquivo.mp4"
        } else {
            a.download = nome || "arquivo.pdf";
        }
        a.click();

        // limpar iframe
        iframe.remove();

        console.log("Arquivo salvo:", nome);
    }
}

